import{_ as l,o as i,c as e,a7 as r}from"./chunks/framework.C5fSpjcB.js";const m=JSON.parse('{"title":"初心者ガイド","description":"","frontmatter":{},"headers":[],"relativePath":"ja/guides/beginner.md","filePath":"ja/guides/beginner.md","lastUpdated":1775394001000}'),t={name:"ja/guides/beginner.md"};function o(s,a,n,h,d,c){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="初心者ガイド" tabindex="-1">初心者ガイド <a class="header-anchor" href="#初心者ガイド" aria-label="Permalink to &quot;初心者ガイド&quot;">​</a></h1><p>忘却前夜（Morimens）を始めたばかりのプレイヤー向けの攻略ガイドです。</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><span class="server-badge server-jp">JP</span> JPサーバーはCN/グローバルサーバーとバランス調整が異なります！ CN版の攻略情報をそのまま適用すると最適でない場合があるため、JP版の環境に合わせた立ち回りを心がけましょう。</p></div><h2 id="リセマラ" tabindex="-1">リセマラ <a class="header-anchor" href="#リセマラ" aria-label="Permalink to &quot;リセマラ&quot;">​</a></h2><h3 id="リセマラの目安" tabindex="-1">リセマラの目安 <a class="header-anchor" href="#リセマラの目安" aria-label="Permalink to &quot;リセマラの目安&quot;">​</a></h3><ul><li><strong>SSR覚醒体1体</strong>を目標にリセマラ</li><li>SSR排出率は<strong>3%</strong>、30連で天井</li><li>初回ガチャで引き直し機能がある場合はそちらを活用</li></ul><h3 id="おすすめ初期覚醒体" tabindex="-1">おすすめ初期覚醒体 <a class="header-anchor" href="#おすすめ初期覚醒体" aria-label="Permalink to &quot;おすすめ初期覚醒体&quot;">​</a></h3><p><em>準備中...</em></p><h2 id="序盤の進め方" tabindex="-1">序盤の進め方 <a class="header-anchor" href="#序盤の進め方" aria-label="Permalink to &quot;序盤の進め方&quot;">​</a></h2><h3 id="_1日目-チュートリアル〜メインステージ序盤" tabindex="-1">1日目：チュートリアル〜メインステージ序盤 <a class="header-anchor" href="#_1日目-チュートリアル〜メインステージ序盤" aria-label="Permalink to &quot;1日目：チュートリアル〜メインステージ序盤&quot;">​</a></h3><ol><li>チュートリアルを完了する</li><li>初回召喚（ガチャ）を引く</li><li>メインステージを進められるところまで進める</li><li>各種コンテンツの解放を目指す</li></ol><h3 id="_2〜3日目-育成開始" tabindex="-1">2〜3日目：育成開始 <a class="header-anchor" href="#_2〜3日目-育成開始" aria-label="Permalink to &quot;2〜3日目：育成開始&quot;">​</a></h3><ol><li>メインアタッカーのレベルを優先的に上げる</li><li>指令カードをLv.3まで強化</li><li>資源ステージの周回を開始</li><li>派遣を設定する</li></ol><h3 id="_1週間目-コンテンツ本格参加" tabindex="-1">1週間目：コンテンツ本格参加 <a class="header-anchor" href="#_1週間目-コンテンツ本格参加" aria-label="Permalink to &quot;1週間目：コンテンツ本格参加&quot;">​</a></h3><ol><li>調査行動（ローグライト）に挑戦</li><li>密契の収集・装備を開始</li><li>刻印の基本装備を整える</li><li>編成を4体揃える</li></ol><h2 id="育成の優先順位" tabindex="-1">育成の優先順位 <a class="header-anchor" href="#育成の優先順位" aria-label="Permalink to &quot;育成の優先順位&quot;">​</a></h2><ol><li><strong>メインアタッカー</strong> — レベル・カード強化を最優先</li><li><strong>ヒーラー/シールダー</strong> — 2番手で育成</li><li><strong>サブアタッカー</strong> — 3番手</li><li><strong>妨害型</strong> — 最後でOK</li></ol><h2 id="算力-arithmetica-の基本" tabindex="-1">算力（Arithmetica）の基本 <a class="header-anchor" href="#算力-arithmetica-の基本" aria-label="Permalink to &quot;算力（Arithmetica）の基本&quot;">​</a></h2><ul><li>毎ターン<strong>5算力</strong>が回復</li><li>カードのコスト分だけ消費</li><li>5算力を使い切るのが基本。余らせるのはもったいない</li></ul><h2 id="狂気-madness-の基本" tabindex="-1">狂気（Madness）の基本 <a class="header-anchor" href="#狂気-madness-の基本" aria-label="Permalink to &quot;狂気（Madness）の基本&quot;">​</a></h2><ul><li><strong>100まで蓄積</strong>すると魂覚醒カード（バースト）が使用可能</li><li>混沌界域の覚醒体は蓄積が速い</li><li>バーストは非常に強力。意図的に溜める戦術も有効</li></ul><h2 id="召喚-ガチャ-の心得" tabindex="-1">召喚（ガチャ）の心得 <a class="header-anchor" href="#召喚-ガチャ-の心得" aria-label="Permalink to &quot;召喚（ガチャ）の心得&quot;">​</a></h2><ul><li>SSR確率<strong>3%</strong>、<strong>30連で天井</strong></li><li>天井分の通貨を貯めてから引く</li><li>ピックアップバナーを優先</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>初心者は恒常ガチャを引かず、ピックアップバナーに通貨を集中投下するのがおすすめです。</p></div><h2 id="やってはいけないこと" tabindex="-1">やってはいけないこと <a class="header-anchor" href="#やってはいけないこと" aria-label="Permalink to &quot;やってはいけないこと&quot;">​</a></h2><ul><li>素材を複数キャラに分散投資（主力1体に集中すべき）</li><li>天井に届かない状態でガチャを引く</li><li>R覚醒体への過度な投資（序盤の繋ぎとして使い、早めにSR/SSRに切り替える）</li><li>刻印の早期厳選（終盤コンテンツ。序盤はメインステ正しいだけで十分）</li></ul><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./../awakeners/leveling.html">育成ガイド</a></li><li><a href="./../modes/gacha.html">召喚システム</a></li><li><a href="./dailies.html">デイリー攻略</a></li><li><a href="./tier-list.html">Tier表</a></li><li><a href="./../awakeners/team-building.html">編成ガイド</a></li></ul>',28)])])}const b=l(t,[["render",o]]);export{m as __pageData,b as default};
